import socket
import threading
import json
import math

class GameServer:
    def __init__(self, host='0.0.0.0', port=12345):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.bind((host, port))
        self.server_socket.listen()
        self.clients = {}
        self.lock = threading.Lock()

    def start(self):
        print("Server started")
        while True:
            client_socket, addr = self.server_socket.accept()
            print(f"Client connected: {addr}")
            threading.Thread(target=self.handle_client, args=(client_socket,)).start()

    def handle_client(self, client_socket):
        player_id = client_socket.recv(1024).decode()
        with self.lock:
            self.clients[player_id] = {'socket': client_socket, 'position': (0, 0, 0)}

        try:
            while True:
                data = client_socket.recv(1024)
                if not data:
                    break
                self.update_player_position(player_id, data)
        finally:
            with self.lock:
                del self.clients[player_id]
            client_socket.close()
            print(f"Client disconnected: {player_id}")

    def update_player_position(self, player_id, data):
        try:
            position = json.loads(data.decode())
            with self.lock:
                self.clients[player_id]['position'] = position
            self.broadcast_game_state()
        except json.JSONDecodeError:
            pass

    def broadcast_game_state(self):
        with self.lock:
            game_state = {pid: info['position'] for pid, info in self.clients.items()}
            for client in self.clients.values():
                try:
                    client['socket'].sendall(json.dumps(game_state).encode())
                except (ConnectionResetError, BrokenPipeError):
                    continue

    def calculate_distance(self, pos1, pos2):
        return math.sqrt(sum((a - b) ** 2 for a, b in zip(pos1, pos2)))

